import os
import secrets
import requests
from flask import Flask, redirect, request, session, url_for, jsonify

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

# OAuth 2.0 Configuration - load from environment variables
OAUTH_CLIENT_ID = os.environ.get('OAUTH_CLIENT_ID')
OAUTH_CLIENT_SECRET = os.environ.get('OAUTH_CLIENT_SECRET')
OAUTH_AUTHORIZATION_URL = os.environ.get('OAUTH_AUTHORIZATION_URL', 'https://authorization-server.example.com/authorize')
OAUTH_TOKEN_URL = os.environ.get('OAUTH_TOKEN_URL', 'https://authorization-server.example.com/token')
OAUTH_USERINFO_URL = os.environ.get('OAUTH_USERINFO_URL', 'https://authorization-server.example.com/userinfo')
OAUTH_REDIRECT_URI = os.environ.get('OAUTH_REDIRECT_URI', 'https://localhost:5000/callback')
OAUTH_SCOPE = os.environ.get('OAUTH_SCOPE', 'openid profile email')

# Validate required configuration at startup
if not OAUTH_CLIENT_ID or not OAUTH_CLIENT_SECRET:
    raise RuntimeError(
        "OAUTH_CLIENT_ID and OAUTH_CLIENT_SECRET environment variables must be set."
    )

# Session configuration for security
app.config.update(
    SESSION_COOKIE_SECURE=True,
    SESSION_COOKIE_HTTPONLY=True,
    SESSION_COOKIE_SAMESITE='Lax',
    PERMANENT_SESSION_LIFETIME=1800,  # 30 minutes
)


@app.route('/')
def index():
    """Home page - shows login status."""
    if 'access_token' in session:
        return jsonify({
            'message': 'You are logged in.',
            'logged_in': True
        })
    return jsonify({
        'message': 'Welcome! Please log in.',
        'logged_in': False,
        'login_url': url_for('login', _external=True)
    })


@app.route('/login')
def login():
    """Initiates the OAuth 2.0 authorization code flow."""
    # Generate a cryptographically secure state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state

    # Build the authorization URL
    authorization_params = {
        'response_type': 'code',
        'client_id': OAUTH_CLIENT_ID,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'scope': OAUTH_SCOPE,
        'state': state,
    }

    # Construct the full authorization URL
    auth_url = requests.Request(
        'GET',
        OAUTH_AUTHORIZATION_URL,
        params=authorization_params
    ).prepare().url

    return redirect(auth_url)


@app.route('/callback')
def callback():
    """Handles the OAuth 2.0 callback and exchanges the authorization code for an access token."""
    # Check for errors from the authorization server
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        app.logger.error(f"OAuth error: {error} - {error_description}")
        return jsonify({
            'error': 'Authorization failed',
            'details': error_description
        }), 400

    # Validate the state parameter to prevent CSRF attacks
    returned_state = request.args.get('state')
    stored_state = session.pop('oauth_state', None)

    if not returned_state or not stored_state:
        app.logger.warning("Missing state parameter in OAuth callback.")
        return jsonify({'error': 'Missing state parameter'}), 400

    if not secrets.compare_digest(returned_state, stored_state):
        app.logger.warning("State parameter mismatch - possible CSRF attack.")
        return jsonify({'error': 'Invalid state parameter'}), 403

    # Get the authorization code
    authorization_code = request.args.get('code')
    if not authorization_code:
        app.logger.warning("Missing authorization code in OAuth callback.")
        return jsonify({'error': 'Missing authorization code'}), 400

    # Exchange the authorization code for an access token
    token_request_data = {
        'grant_type': 'authorization_code',
        'code': authorization_code,
        'redirect_uri': OAUTH_REDIRECT_URI,
        'client_id': OAUTH_CLIENT_ID,
        'client_secret': OAUTH_CLIENT_SECRET,
    }

    try:
        token_response = requests.post(
            OAUTH_TOKEN_URL,
            data=token_request_data,
            headers={
                'Content-Type': 'application/x-www-form-urlencoded',
                'Accept': 'application/json',
            },
            timeout=30,
        )
        token_response.raise_for_status()
    except requests.exceptions.Timeout:
        app.logger.error("Token exchange request timed out.")
        return jsonify({'error': 'Token exchange timed out'}), 504
    except requests.exceptions.ConnectionError:
        app.logger.error("Failed to connect to token endpoint.")
        return jsonify({'error': 'Failed to connect to authorization server'}), 502
    except requests.exceptions.HTTPError as e:
        app.logger.error(f"Token exchange failed with status {e.response.status_code}")
        return jsonify({'error': 'Token exchange failed'}), 502
    except requests.exceptions.RequestException as e:
        app.logger.error(f"Token exchange request failed: {e}")
        return jsonify({'error': 'Token exchange failed'}), 500

    # Parse the token response
    try:
        token_data = token_response.json()
    except ValueError:
        app.logger.error("Invalid JSON in token response.")
        return jsonify({'error': 'Invalid token response'}), 502

    access_token = token_data.get('access_token')
    if not access_token:
        app.logger.error("No access token in token response.")
        return jsonify({'error': 'No access token received'}), 502

    # Store tokens securely in the session
    session['access_token'] = access_token
    session['token_type'] = token_data.get('token_type', 'Bearer')

    # Store refresh token if provided
    refresh_token = token_data.get('refresh_token')
    if refresh_token:
        session['refresh_token'] = refresh_token

    # Store token expiry if provided
    expires_in = token_data.get('expires_in')
    if expires_in:
        session['token_expires_in'] = expires_in

    session.permanent = True

    app.logger.info("User successfully authenticated via OAuth.")

    return redirect(url_for('profile'))


@app.route('/profile')
def profile():
    """Fetches and displays user profile information using the access token."""
    access_token = session.get('access_token')
    if not access_token:
        return redirect(url_for('login'))

    token_type = session.get('token_type', 'Bearer')

    try:
        userinfo_response = requests.get(
            OAUTH_USERINFO_URL,
            headers={
                'Authorization': f'{token_type} {access_token}',
                'Accept': 'application/json',
            },
            timeout=30,
        )
        userinfo_response.raise_for_status()
    except requests.exceptions.HTTPError as e:
        if e.response.status_code == 401:
            # Token might be expired, clear session and re-authenticate
            session.clear()
            app.logger.info("Access token expired or invalid, redirecting to login.")
            return redirect(url_for('login'))
        app.logger.error(f"Userinfo request failed: {e}")
        return jsonify({'error': 'Failed to fetch user info'}), 502
    except requests.exceptions.RequestException as e:
        app.logger.error(f"Userinfo request failed: {e}")
        return jsonify({'error': 'Failed to fetch user info'}), 500

    try:
        user_info = userinfo_response.json()
    except ValueError:
        return jsonify({'error': 'Invalid userinfo response'}), 502

    return jsonify({
        'message': 'User profile',
        'user': user_info
    })


@app.route('/logout')
def logout():
    """Clears the session and logs the user out."""
    session.clear()
    return jsonify({
        'message': 'Successfully logged out.',
        'login_url': url_for('login', _external=True)
    })


